          { "proofNode": "0x<Leaf>",     "nextBeginOffset": 0,  "nextEndOffset": 0  }
        ]
      },
      {
        "slotIndex": 7,
        "leftmostLeafKey": "0x<sibling leaf key>",
        "proofPath": [
