// ============================
// Action Constants
// ============================
library Actions {
    uint8 internal constant MINT_POSITION = 0x02;
    uint8 internal constant SETTLE_PAIR = 0x0d;
    uint8 internal constant SWEEP = 0x14;
    uint8 internal constant INCREASE_LIQUIDITY = 0x00;
    uint8 internal constant DECREASE_LIQUIDITY = 0x01;
    uint8 internal constant BURN_POSITION = 0x03;
    uint8 internal constant SETTLE_ALL = 0x0c;
    uint8 internal constant TAKE_ALL = 0x0f;
}

// ============================
// Market Maker Contract
// ============================
contract MarketMaker {
    IPositionManager public immutable positionManager;
    IAllowanceTransfer public immutable permit2;
    address public immutable router;

# 6.AMM DEX Integration

// Approved tokens
    mapping(address => bool) public approved;

constructor(address _posm, address _permit2, address _router) {
        positionManager = IPositionManager(_posm);
        permit2 = IAllowanceTransfer(_permit2);
        router = _router;
    }

/**
     * @notice Step 1: Approve token (call once per token)
     */
    function approveToken(address token) external {
        // 1. Approve Permit2 as unlimited spender
        IERC20(token).approve(address(permit2), type(uint256).max);
        // 2. Approve PositionManager via Permit2
        permit2.approve(
            token,
            address(positionManager),
            type(uint160).max,
            type(uint48).max
        );
        approved[token] = true;
    }

# 6.AMM DEX Integration

/**
     * @notice Step 2: Mint new liquidity position (add liquidity)
     * @param poolKey Pool configuration
     * @param tickLower Lower price bound tick
     * @param tickUpper Upper price bound tick
     * @param liquidity Amount of liquidity
     * @param amount0Max Maximum token0 to spend
     * @param amount1Max Maximum token1 to spend
     * @return tokenId Position NFT ID
     */
    function mintPosition(
        PoolKey calldata poolKey,
        int24 tickLower,
        int24 tickUpper,
        uint256 liquidity,
        uint128 amount0Max,
        uint128 amount1Max
    ) external returns (uint256 tokenId) {
        require(approved[Currency.unwrap(poolKey.currency0)], "Token0 not approved");
        require(approved[Currency.unwrap(poolKey.currency1)], "Token1 not approved");

// Encode action sequence
        bytes memory actions = abi.encodePacked(
            uint8(Actions.MINT_POSITION),
            uint8(Actions.SETTLE_PAIR)
        );

bytes[] memory params = new bytes[](2);

# 6.AMM DEX Integration

// MINT_POSITION parameters
        params[0] = abi.encode(
            poolKey,       // pool config
            tickLower,     // lower price bound
            tickUpper,     // upper price bound
            liquidity,     // liquidity amount
            amount0Max,    // max token0 spend
            amount1Max,    // max token1 spend
            msg.sender,    // NFT recipient
            bytes("")      // hookData
        );

// SETTLE_PAIR parameters: specify tokens to settle
        params[1] = abi.encode(
            poolKey.currency0,
            poolKey.currency1
        );

// Execute: call modifyLiquidities
        positionManager.modifyLiquidities(
            abi.encode(actions, params),
            block.timestamp + 60  // 60s deadline
        );

// Get the newly minted tokenId (in production, query via events or state)
        tokenId = positionManager.nextTokenId() - 1;
    }

# 6.AMM DEX Integration

/**
     * @notice Add liquidity to an existing position
     */
    function increaseLiquidity(
        PoolKey calldata poolKey,
        uint256 tokenId,
        uint256 liquidity,
        uint128 amount0Max,
        uint128 amount1Max
    ) external {
        bytes memory actions = abi.encodePacked(
            uint8(Actions.INCREASE_LIQUIDITY),
            uint8(Actions.SETTLE_PAIR)
        );

bytes[] memory params = new bytes[](2);
        params[0] = abi.encode(tokenId, liquidity, amount0Max, amount1Max, bytes(""));
        params[1] = abi.encode(poolKey.currency0, poolKey.currency1);

positionManager.modifyLiquidities(
            abi.encode(actions, params),
            block.timestamp + 60
        );
    }
