  })

# 6.AMM DEX Integration

await publicClient.waitForTransactionReceipt({ hash: txHash })

const liquidityToRemove = (positionDetails.liquidity * BigInt(Math.floor(percentageToRemove * 10_000))) / 10_000n

return { txHash, removedLiquidity: liquidityToRemove }
}
