function swapExactInputSingle(
    PoolKey calldata key,
    uint128 amountIn,
    uint128 minAmountOut
) external returns (uint256 amountOut) {
    // Encode command
    bytes memory commands = abi.encodePacked(uint8(Commands.V4_SWAP));
    bytes[] memory inputs = new bytes[](1);

// Encode actions: SWAP → SETTLE → TAKE
    bytes memory actions = abi.encodePacked(
        uint8(Actions.SWAP_EXACT_IN_SINGLE),
        uint8(Actions.SETTLE_ALL),
        uint8(Actions.TAKE_ALL)
    );

// Parameters for each action
    bytes[] memory params = new bytes[](3);

// 1. SWAP_EXACT_IN_SINGLE parameters
    params[0] = abi.encode(
        ExactInputSingleParams({
            poolKey: key,
            zeroForOne: true,          // true: token0 → token1
            amountIn: amountIn,
            amountOutMinimum: minAmountOut,
            hookData: bytes("")
        })
    );

// 2. SETTLE_ALL parameters: input token + max payment
    params[1] = abi.encode(key.currency0, amountIn);

# 6.AMM DEX Integration

// 3. TAKE_ALL parameters: output token + minimum receive
    params[2] = abi.encode(key.currency1, minAmountOut);

// Combine
    inputs[0] = abi.encode(actions, params);

// Execute
    uint256 deadline = block.timestamp + 20;
    router.execute(commands, inputs, deadline);

// Verify output
    amountOut = key.currency1.balanceOf(address(this));
    require(amountOut >= minAmountOut, "Insufficient output amount");
}

