### V. Key Parameter Calculations <a href="#v-key-parameter-calculations" id="v-key-parameter-calculations"></a>

#### Tick ↔ Price Conversion <a href="#tick--price-conversion" id="tick--price-conversion"></a>

```typescript
const LOG_1_0001 = Math.log(1.0001)

function priceToTick(price: number): number {
  return Math.floor(Math.log(price) / LOG_1_0001)
}

function tickToPrice(tick: number): number {
  return Math.pow(1.0001, tick)
}

# 6.AMM DEX Integration

function tickToSqrtPriceX96(tick: number): bigint {
  const price = Math.sqrt(Math.pow(1.0001, tick))
  return BigInt(Math.floor(price * 2n ** 96n))
}
```

#### Liquidity Calculation <a href="#liquidity-calculation" id="liquidity-calculation"></a>

```typescript
function calculateLiquidity(
  sqrtPriceCurrent: bigint,
  sqrtPriceLower: bigint,
  sqrtPriceUpper: bigint,
  maxAmount0: bigint,
  maxAmount1: bigint
): bigint {
  if (sqrtPriceCurrent <= sqrtPriceLower) {
    // Price below range: only need token0
    return getLiquidityForAmount0(sqrtPriceLower, sqrtPriceUpper, maxAmount0)
  } else if (sqrtPriceCurrent >= sqrtPriceUpper) {
    // Price above range: only need token1
    return getLiquidityForAmount1(sqrtPriceLower, sqrtPriceUpper, maxAmount1)
  } else {
    // Price within range: need both tokens
    const liq0 = getLiquidityForAmount0(sqrtPriceCurrent, sqrtPriceUpper, maxAmount0)
    const liq1 = getLiquidityForAmount1(sqrtPriceLower, sqrtPriceCurrent, maxAmount1)
    return liq0 < liq1 ? liq0 : liq1  // take the smaller value
  }
}

# 6.AMM DEX Integration

function getLiquidityForAmount0(
  sqrtPriceA: bigint, sqrtPriceB: bigint, amount: bigint
): bigint {
  if (sqrtPriceA > sqrtPriceB) [sqrtPriceA, sqrtPriceB] = [sqrtPriceB, sqrtPriceA]
  const intermediate = (sqrtPriceA * sqrtPriceB) / (2n ** 96n)
  return (amount * intermediate) / (sqrtPriceB - sqrtPriceA)
}

function getLiquidityForAmount1(
  sqrtPriceA: bigint, sqrtPriceB: bigint, amount: bigint
): bigint {
  if (sqrtPriceA > sqrtPriceB) [sqrtPriceA, sqrtPriceB] = [sqrtPriceB, sqrtPriceA]
  return (amount * (2n ** 96n)) / (sqrtPriceB - sqrtPriceA)
}
```

